    11→// SubscriptionsStore defines the persistence operations for subscriptions.
    12→type SubscriptionsStore interface {
    13→	ListSubscriptions(ctx context.Context, page, perPage int) ([]models.Subscription, int, error)
    14→	CreateSubscription(ctx context.Context, sub *models.Subscription) error
    15→	GetSubscription(ctx context.Context, id string) (*models.Subscription, error)
    16→	UpdateSubscription(ctx context.Context, id string, sub *models.Subscription) error
    17→	DeleteSubscription(ctx context.Context, id string) error
    18→}
    19→
    20→// SubscriptionsHandler implements HTTP handlers for the /subscriptions resource.
    21→type SubscriptionsHandler struct {
    22→	store SubscriptionsStore
    23→}
    24→
    25→// NewSubscriptionsHandler returns a new SubscriptionsHandler.
    26→func NewSubscriptionsHandler(store SubscriptionsStore) *SubscriptionsHandler {
    27→	return &SubscriptionsHandler{store: store}
    28→}
    29→
    30→// List handles GET /subscriptions — returns a paginated list of subscriptions.
    31→func (h *SubscriptionsHandler) List(w http.ResponseWriter, r *http.Request) {
    32→	page, perPage := ParsePagination(r)
    33→	subs, total, err := h.store.ListSubscriptions(r.Context(), page, perPage)
    34→	if err != nil {
    35→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list subscriptions")
    36→		return
    37→	}
    38→	if subs == nil {
    39→		subs = []models.Subscription{}
    40→	}
    41→	RespondList(w, r, http.StatusOK, subs, page, perPage, total)
    42→}
    43→
    44→// Create handles POST /subscriptions — creates a new subscription.
    45→func (h *SubscriptionsHandler) Create(w http.ResponseWriter, r *http.Request) {
    46→	var sub models.Subscription
    47→	if err := DecodeJSON(r, &sub); err != nil {
    48→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    49→		return
    50→	}
    51→	sub.Type = strings.TrimSpace(sub.Type)
    52→	sub.ChannelID = strings.TrimSpace(sub.ChannelID)
    53→	// Validate type is source or project.
    54→	if sub.Type != "source" && sub.Type != "project" {
    55→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "type must be 'source' or 'project'")
    56→		return
    57→	}
    58→	if sub.ChannelID == "" {
    59→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "channel_id is required")
    60→		return
    61→	}
    62→	// Validate that the corresponding ID is set for the type.
    63→	if sub.Type == "source" && (sub.SourceID == nil || *sub.SourceID == "") {
    64→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "source_id is required when type is 'source'")
    65→		return
    66→	}
    67→	if sub.Type == "project" && (sub.ProjectID == nil || *sub.ProjectID == "") {
    68→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "project_id is required when type is 'project'")
    69→		return
    70→	}
    71→	if err := h.store.CreateSubscription(r.Context(), &sub); err != nil {
    72→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to create subscription")
    73→		return
    74→	}
    75→	RespondJSON(w, r, http.StatusCreated, sub)
    76→}
    77→
    78→// Get handles GET /subscriptions/{id} — returns a single subscription.
    79→func (h *SubscriptionsHandler) Get(w http.ResponseWriter, r *http.Request) {
    80→	id := r.PathValue("id")
    81→	if id == "" {
    82→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid subscription ID")
    83→		return
    84→	}
    85→	sub, err := h.store.GetSubscription(r.Context(), id)
    86→	if err != nil {
    87→		RespondError(w, r, http.StatusNotFound, "not_found", "Subscription not found")
    88→		return
    89→	}
    90→	RespondJSON(w, r, http.StatusOK, sub)
    91→}
    92→
    93→// Update handles PUT /subscriptions/{id} — updates an existing subscription.
    94→func (h *SubscriptionsHandler) Update(w http.ResponseWriter, r *http.Request) {
    95→	id := r.PathValue("id")
    96→	if id == "" {
    97→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid subscription ID")
    98→		return
    99→	}
   100→	var sub models.Subscription
   101→	if err := DecodeJSON(r, &sub); err != nil {
   102→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
   103→		return
   104→	}
   105→	sub.Type = strings.TrimSpace(sub.Type)
   106→	sub.ChannelID = strings.TrimSpace(sub.ChannelID)
   107→	if sub.Type != "source" && sub.Type != "project" {
   108→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "type must be 'source' or 'project'")
   109→		return
   110→	}
   111→	if sub.ChannelID == "" {
   112→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "channel_id is required")
   113→		return
   114→	}
   115→	if sub.Type == "source" && (sub.SourceID == nil || *sub.SourceID == "") {
   116→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "source_id is required when type is 'source'")
   117→		return
   118→	}
   119→	if sub.Type == "project" && (sub.ProjectID == nil || *sub.ProjectID == "") {
   120→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "project_id is required when type is 'project'")
   121→		return
   122→	}
   123→	if err := h.store.UpdateSubscription(r.Context(), id, &sub); err != nil {
   124→		RespondError(w, r, http.StatusNotFound, "not_found", "Subscription not found")
   125→		return
   126→	}
   127→	sub.ID = id
   128→	RespondJSON(w, r, http.StatusOK, sub)
   129→}
   130→
   131→// Delete handles DELETE /subscriptions/{id} — deletes a subscription.
   132→func (h *SubscriptionsHandler) Delete(w http.ResponseWriter, r *http.Request) {
   133→	id := r.PathValue("id")
   134→	if id == "" {
   135→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid subscription ID")
   136→		return
   137→	}
   138→	if err := h.store.DeleteSubscription(r.Context(), id); err != nil {
   139→		RespondError(w, r, http.StatusNotFound, "not_found", "Subscription not found")
   140→		return
   141→	}
   142→	w.WriteHeader(http.StatusNoContent)
   143→}
