   745→// UpdateAgentRunStatus sets the status of an agent run and updates the
   746→// started_at timestamp when transitioning to "running".
   747→func (s *PgStore) UpdateAgentRunStatus(ctx context.Context, id, status string) error {
   748→	var query string
   749→	switch status {
   750→	case "running":
   751→		query = `UPDATE agent_runs SET status = $1, started_at = NOW() WHERE id = $2`
   752→	case "completed":
   753→		query = `UPDATE agent_runs SET status = $1, completed_at = NOW() WHERE id = $2`
   754→	default:
   755→		query = `UPDATE agent_runs SET status = $1 WHERE id = $2`
   756→	}
   757→	tag, err := s.pool.Exec(ctx, query, status, id)
   758→	if err != nil {
   759→		return fmt.Errorf("update agent run status: %w", err)
   760→	}
   761→	if tag.RowsAffected() == 0 {
   762→		return fmt.Errorf("agent run not found: %s", id)
   763→	}
   764→	return nil
   765→}
