    21→// ChannelsHandler implements HTTP handlers for the /channels resource.
    22→type ChannelsHandler struct {
    23→	store   ChannelsStore
    24→	senders map[string]routing.Sender
    25→}
    26→
    27→// NewChannelsHandler returns a new ChannelsHandler.
    28→func NewChannelsHandler(store ChannelsStore, senders map[string]routing.Sender) *ChannelsHandler {
