     1→package routing
     2→
     3→import (
     4→	"context"
     5→	"encoding/json"
     6→	"fmt"
     7→	"log/slog"
     8→	"net/http"
     9→	"time"
    10→
    11→	"github.com/riverqueue/river"
    12→	"github.com/sentioxyz/changelogue/internal/models"
    13→	"github.com/sentioxyz/changelogue/internal/queue"
    14→)
    15→
    16→// NotifyStore is the data access interface required by the notification worker.
    17→type NotifyStore interface {
    18→	GetRelease(ctx context.Context, id string) (*models.Release, error)
    19→	GetSource(ctx context.Context, id string) (*models.Source, error)
    20→	ListSourceSubscriptions(ctx context.Context, sourceID string) ([]models.Subscription, error)
    21→	GetChannel(ctx context.Context, id string) (*models.NotificationChannel, error)
    22→	GetProject(ctx context.Context, id string) (*models.Project, error)
    23→	GetPreviousRelease(ctx context.Context, sourceID string, beforeVersion string) (*models.Release, error)
    24→	EnqueueAgentRun(ctx context.Context, projectID, trigger, version string) error
    25→}
    26→
    27→// NotifyWorker is a River worker that processes NotifyJobArgs.
    28→// It looks up the release, finds all source-level subscriptions, resolves
    29→// the notification channel for each, and dispatches via the appropriate sender.
    30→// After sending notifications, it checks the project's agent rules and
    31→// auto-triggers an agent run if the version criteria are met.
    32→type NotifyWorker struct {
    33→	river.WorkerDefaults[queue.NotifyJobArgs]
    34→	store   NotifyStore
    35→	senders map[string]Sender
    36→}
    37→
    38→// NewSenders returns the default sender map for webhook, Slack, and Discord.
    39→func NewSenders() map[string]Sender {
    40→	return map[string]Sender{
    41→		"webhook": &WebhookSender{Client: &http.Client{Timeout: 10 * time.Second}},
    42→		"slack":   &SlackSender{Client: &http.Client{Timeout: 10 * time.Second}},
    43→		"discord": &DiscordSender{Client: &http.Client{Timeout: 10 * time.Second}},
    44→	}
    45→}
    46→
    47→// NewNotifyWorker creates a NotifyWorker with default senders for webhook, Slack, and Discord.
    48→func NewNotifyWorker(store NotifyStore) *NotifyWorker {
    49→	return &NotifyWorker{
    50→		store:   store,
    51→		senders: NewSenders(),
    52→	}
    53→}
    54→
    55→// Work processes a notify job: fetches the release, resolves subscriptions,
    56→// sends notifications to all matching channels, and checks agent rules to
    57→// auto-trigger agent runs when version criteria are met.
    58→func (w *NotifyWorker) Work(ctx context.Context, job *river.Job[queue.NotifyJobArgs]) error {
    59→	release, err := w.store.GetRelease(ctx, job.Args.ReleaseID)
    60→	if err != nil {
    61→		return fmt.Errorf("get release: %w", err)
    62→	}
    63→
    64→	subs, err := w.store.ListSourceSubscriptions(ctx, job.Args.SourceID)
    65→	if err != nil {
    66→		return fmt.Errorf("list subscriptions: %w", err)
    67→	}
    68→
    69→	for _, sub := range subs {
    70→		ch, err := w.store.GetChannel(ctx, sub.ChannelID)
    71→		if err != nil {
    72→			slog.Error("get channel failed", "channel_id", sub.ChannelID, "err", err)
    73→			continue
    74→		}
    75→
    76→		sender, ok := w.senders[ch.Type]
    77→		if !ok {
    78→			slog.Warn("unknown channel type", "type", ch.Type)
    79→			continue
    80→		}
    81→
    82→		msg := Notification{
    83→			Title:   fmt.Sprintf("New release: %s", release.Version),
    84→			Body:    string(release.RawData),
    85→			Version: release.Version,
    86→		}
    87→
    88→		if err := sender.Send(ctx, ch, msg); err != nil {
    89→			slog.Error("send notification failed", "channel", ch.Name, "err", err)
    90→		}
    91→	}
    92→
    93→	// Check agent rules and auto-trigger if criteria are met.
    94→	w.checkAgentRules(ctx, release, job.Args.SourceID)
    95→
    96→	return nil
    97→}
    98→
    99→// checkAgentRules evaluates the project's agent rules against the new release
   100→// and the previous release for this source. If any rule matches, an agent run
   101→// is enqueued. Errors are logged but do not fail the job — notification delivery
   102→// is the primary responsibility.
   103→func (w *NotifyWorker) checkAgentRules(ctx context.Context, release *models.Release, sourceID string) {
   104→	source, err := w.store.GetSource(ctx, sourceID)
   105→	if err != nil {
   106→		slog.Error("get source for agent rules", "source_id", sourceID, "err", err)
   107→		return
   108→	}
   109→
   110→	project, err := w.store.GetProject(ctx, source.ProjectID)
   111→	if err != nil {
   112→		slog.Error("get project for agent rules", "project_id", source.ProjectID, "err", err)
   113→		return
   114→	}
   115→
   116→	// Parse the project's agent_rules JSON.
   117→	var rules models.AgentRules
   118→	if len(project.AgentRules) > 0 {
   119→		if err := json.Unmarshal(project.AgentRules, &rules); err != nil {
   120→			slog.Error("unmarshal agent rules", "project_id", project.ID, "err", err)
   121→			return
   122→		}
   123→	}
   124→
   125→	// Determine the previous version for comparison.
   126→	var previousVersion string
   127→	prev, err := w.store.GetPreviousRelease(ctx, sourceID, release.Version)
   128→	if err != nil {
   129→		slog.Error("get previous release for agent rules", "source_id", sourceID, "err", err)
   130→		return
   131→	}
   132→	if prev != nil {
   133→		previousVersion = prev.Version
   134→	}
   135→
   136→	if CheckAgentRules(&rules, release.Version, previousVersion) {
   137→		trigger := fmt.Sprintf("auto:version:%s", release.Version)
   138→		if err := w.store.EnqueueAgentRun(ctx, source.ProjectID, trigger, release.Version); err != nil {
   139→			slog.Error("enqueue agent run", "project_id", source.ProjectID, "err", err)
   140→		} else {
   141→			slog.Info("agent run triggered by version rules",
   142→				"project_id", source.ProjectID,
   143→				"version", release.Version,
   144→				"previous_version", previousVersion,
   145→			)
   146→		}
   147→	}
   148→}
