     3→import (
     4→	"bytes"
     5→	"context"
     6→	"encoding/json"
     7→	"fmt"
     8→	"net/http"
     9→
    10→	"github.com/sentioxyz/changelogue/internal/models"
    11→)
    12→
    13→type webhookConfig struct {
    14→	URL string `json:"url"`
    15→}
    16→
    17→// WebhookSender sends notifications as JSON POST requests to a configured URL.
    18→type WebhookSender struct {
    19→	Client *http.Client
    20→}
    21→
    22→// webhookSemanticPayload is the structured webhook payload for semantic reports.
    23→type webhookSemanticPayload struct {
    24→	Title   string                `json:"title"`
    25→	Version string                `json:"version"`
    26→	Report  *models.SemanticReport `json:"report"`
    27→}
    28→
    29→func (s *WebhookSender) Send(ctx context.Context, ch *models.NotificationChannel, msg Notification) error {
    30→	var cfg webhookConfig
    31→	if err := json.Unmarshal(ch.Config, &cfg); err != nil {
    32→		return fmt.Errorf("parse webhook config: %w", err)
    33→	}
    34→
    35→	// Try to parse body as SemanticReport for structured output.
    36→	var payload any
    37→	var report models.SemanticReport
    38→	if err := json.Unmarshal([]byte(msg.Body), &report); err == nil && report.Subject != "" {
    39→		payload = webhookSemanticPayload{
    40→			Title:   msg.Title,
    41→			Version: msg.Version,
    42→			Report:  &report,
    43→		}
    44→	} else {
    45→		payload = msg
    46→	}
    47→
    48→	body, err := json.Marshal(payload)
    49→	if err != nil {
    50→		return fmt.Errorf("marshal notification: %w", err)
    51→	}
    52→
    53→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, cfg.URL, bytes.NewReader(body))
    54→	if err != nil {
    55→		return fmt.Errorf("create request: %w", err)
    56→	}
    57→	req.Header.Set("Content-Type", "application/json")
    58→
    59→	client := s.Client
    60→	if client == nil {
    61→		client = http.DefaultClient
    62→	}
    63→
    64→	resp, err := client.Do(req)
    65→	if err != nil {
    66→		return fmt.Errorf("send webhook: %w", err)
    67→	}
    68→	defer resp.Body.Close()
    69→
    70→	if resp.StatusCode >= 400 {
    71→		return fmt.Errorf("webhook returned status %d", resp.StatusCode)
    72→	}
    73→	return nil
    74→}
