      setSelectedProjectIds([...allProjectIds]);
    }
  };

  const toggleAllSources = () => {
    if (selectedSourceIds.length === allSourceIds.length) {
      setSelectedSourceIds([]);
    } else {
      setSelectedSourceIds([...allSourceIds]);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSaving(true);
