   710→// EnqueueAgentRun creates an agent_run row and enqueues a River AgentJobArgs.
   711→// This follows the transactional outbox pattern for zero-loss guarantee.
   712→func (s *PgStore) EnqueueAgentRun(ctx context.Context, projectID, trigger, version string) error {
   713→	tx, err := s.pool.Begin(ctx)
   714→	if err != nil {
   715→		return fmt.Errorf("begin tx: %w", err)
   716→	}
   717→	defer tx.Rollback(ctx)
   718→
   719→	var runID string
   720→	err = tx.QueryRow(ctx,
   721→		`INSERT INTO agent_runs (project_id, trigger, version, status)
   722→		 VALUES ($1, $2, $3, 'pending')
   723→		 RETURNING id`, projectID, trigger, version,
   724→	).Scan(&runID)
   725→	if err != nil {
   726→		return fmt.Errorf("insert agent run: %w", err)
   727→	}
   728→
   729→	if s.river != nil {
   730→		_, err = s.river.InsertTx(ctx, tx, queue.AgentJobArgs{
   731→			AgentRunID: runID,
   732→			ProjectID:  projectID,
   733→			Version:    version,
   734→		}, nil)
   735→		if err != nil {
   736→			return fmt.Errorf("enqueue agent job: %w", err)
   737→		}
   738→	}
   739→
   740→	return tx.Commit(ctx)
   741→}
